sql:
SELECT AVG(difficulty) AS avg_difficulty
FROM trails
WHERE trail_id IN (
    SELECT DISTINCT trail_id
    FROM trail_reviews
);

external_knowledge:
- "Most beloved" implies a combination of high usage and high points earned;
- "Usage frequency" refers to the number of times a trail is used;
- "Points earned" are part of a loyalty program that rewards skiers for using trails.

sql:
SELECT COUNT(DISTINCT trail_id) AS trail_count
FROM trail_history
WHERE change_author = 'Admin2';

external_knowledge:
- "Most frequently used" refers to the trails with the highest usage count;
- "Highest-rated" refers to the trails with the highest average rating;
- The query considers the top 3 most frequently used trails for each skier.

sql:
SELECT COUNT(safety_id) 
FROM trail_safety 
WHERE safety_notes LIKE '%mogul%';

SELECT skier_name, loyalty_points
FROM skiers
WHERE loyalty_points > 10;

SELECT COUNT(review_id) 
FROM trail_reviews 
WHERE rating > 4;

external_knowledge:
